import{_ as r,o as t,c as n,j as e,a as s,a1 as o}from"./chunks/framework.Bp7r_-XI.js";const f=JSON.parse('{"title":"多功能铲","description":"","frontmatter":{},"headers":[],"relativePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/多功能铲.md","filePath":"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/多功能铲.md"}'),d={name:"4.资源分区/7.物品与装备/2.武器/近战武器/1.D级/多功能铲.md"};function l(p,a,_,i,c,h){return t(),n("div",null,[...a[0]||(a[0]=[e("h1",{id:"多功能铲",tabindex:"-1"},[s("多功能铲 "),e("a",{class:"header-anchor",href:"#多功能铲","aria-label":'Permalink to "多功能铲"'},"​")],-1),e("table",{class:"bannerparthead"},[e("tbody",null,[e("tr",{id:"hdr"},[e("td",{class:"runninghead",nowrap:""},"TMD：汹涌疾风027")])])],-1),o('<h1 id="多功能铲-1" tabindex="-1">多功能铲 <a class="header-anchor" href="#多功能铲-1" aria-label="Permalink to &quot;多功能铲&quot;">​</a></h1><p>多功能铲<br> D+500<br> 武器分类：铲<br> 武器伤害6L，武器体积3，力量需求3</p><p>这是一把多功能的铲子，其铲刃左侧带锯齿，右侧则是刃口，因此你既可以用它锯木头，也可以拿它切菜做饭，<br> 在铲柄有一个钳子，可以轻易剪短铁丝网，<br> 使用机关将铲刃弯下，其更是能作为锄头使用，<br> 并且将其铲柄拆开，内里还有一根鱼线和一根能用来生活做饭的镁棒，拆下来的铲柄更是有着手电筒的功能，并且可以随时组装。</p><p>而在有着如此之多的效果之外，这把铲子甚至还能作为盾牌使用，<br> 如果作为盾牌，其将具有武器伤害2L，格挡6的效果，切换是一个迅捷动作，并且这把铲子具有【防弹】效果，没错，是这把铲子防弹而不是你。<br> ————————</p><hr><p>Copyright ? 2025 <a href="http://www.goddessfantasy.net/bbs/index.php?board=2008.0" target="_blank" rel="noreferrer">TMDtrpg制作组</a>. All Rights Reserved.</p>',6)])])}const m=r(d,[["render",l]]);export{f as __pageData,m as default};
